import React, { useState, useEffect } from 'react';
import { deliveriesAPI } from '../services/api';

function DeliveryCalendar() {
  const [deliveries, setDeliveries] = useState([]);
  const [calendarData, setCalendarData] = useState({});
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDate, setSelectedDate] = useState(null);
  const [showModal, setShowModal] = useState(false);

  useEffect(() => {
    fetchDeliveries();
  }, []);

  const fetchDeliveries = async () => {
    try {
      setLoading(true);
      const [deliveriesRes, calendarRes] = await Promise.all([
        deliveriesAPI.getAll().catch(() => ({ data: [] })),
        deliveriesAPI.getCalendar().catch(() => ({ data: {} })),
      ]);
      setDeliveries(deliveriesRes.data);
      setCalendarData(calendarRes.data || {});
      setError(null);
    } catch (err) {
      setError('Failed to load deliveries');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const getDaysInMonth = (date) => {
    const year = date.getFullYear();
    const month = date.getMonth();
    const firstDay = new Date(year, month, 1);
    const lastDay = new Date(year, month + 1, 0);
    const daysInMonth = lastDay.getDate();
    const startingDay = firstDay.getDay();

    const days = [];

    // Add empty cells for days before the first day of the month
    for (let i = 0; i < startingDay; i++) {
      days.push({ day: null, date: null });
    }

    // Add days of the month
    for (let day = 1; day <= daysInMonth; day++) {
      const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(
        day
      ).padStart(2, '0')}`;
      days.push({ day, date: dateStr });
    }

    return days;
  };

  const getDeliveriesForDate = (dateStr) => {
    return deliveries.filter((delivery) => {
      if (!delivery.scheduled_date) return false;
      return delivery.scheduled_date.startsWith(dateStr);
    });
  };

  const formatDate = (dateStr) => {
    return new Date(dateStr).toLocaleDateString('en-US', {
      weekday: 'long',
      month: 'long',
      day: 'numeric',
      year: 'numeric',
    });
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'completed':
        return '#27ae60';
      case 'in_transit':
        return '#3498db';
      case 'pending':
        return '#f39c12';
      case 'cancelled':
        return '#e74c3c';
      default:
        return '#95a5a6';
    }
  };

  const prevMonth = () => {
    setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1));
  };

  const nextMonth = () => {
    setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1));
  };

  const goToToday = () => {
    setCurrentDate(new Date());
  };

  const handleDateClick = (dateStr) => {
    setSelectedDate(dateStr);
    setShowModal(true);
  };

  const monthNames = [
    'January',
    'February',
    'March',
    'April',
    'May',
    'June',
    'July',
    'August',
    'September',
    'October',
    'November',
    'December',
  ];

  const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];

  if (loading) {
    return <div className="loading">Loading calendar...</div>;
  }

  const days = getDaysInMonth(currentDate);
  const selectedDateDeliveries = selectedDate
    ? getDeliveriesForDate(selectedDate)
    : [];

  return (
    <div>
      <div className="page-header">
        <h1>Delivery Calendar</h1>
      </div>

      {error && <div className="error">{error}</div>}

      <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '20px' }}>
        <div className="card">
          <div className="calendar-header">
            <button className="btn btn-primary" onClick={prevMonth}>
              ← Previous
            </button>
            <h3>
              {monthNames[currentDate.getMonth()]} {currentDate.getFullYear()}
            </h3>
            <div style={{ display: 'flex', gap: '10px' }}>
              <button className="btn btn-primary" onClick={goToToday}>
                Today
              </button>
              <button className="btn btn-primary" onClick={nextMonth}>
                Next →
              </button>
            </div>
          </div>

          <div className="calendar-grid">
            {dayNames.map((day) => (
              <div
                key={day}
                style={{
                  padding: '10px',
                  textAlign: 'center',
                  fontWeight: 'bold',
                  color: '#2c3e50',
                }}
              >
                {day}
              </div>
            ))}
            {days.map((dayObj, index) => {
              const hasDeliveries = dayObj.date && getDeliveriesForDate(dayObj.date).length > 0;
              const isToday =
                dayObj.date ===
                new Date().toISOString().split('T')[0];

              return (
                <div
                  key={index}
                  className={`calendar-day ${hasDeliveries ? 'has-deliveries' : ''}`}
                  onClick={() => dayObj.date && handleDateClick(dayObj.date)}
                  style={{
                    cursor: dayObj.date ? 'pointer' : 'default',
                    backgroundColor: isToday ? '#e3f2fd' : undefined,
                    border: isToday ? '2px solid #2196f3' : undefined,
                  }}
                >
                  {dayObj.day && (
                    <>
                      <span className="date">{dayObj.day}</span>
                      {hasDeliveries && (
                        <span className="delivery-count">
                          {getDeliveriesForDate(dayObj.date).length} delivery
                          {getDeliveriesForDate(dayObj.date).length > 1 ? 'ies' : ''}
                        </span>
                      )}
                    </>
                  )}
                </div>
              );
            })}
          </div>
        </div>

        <div className="card">
          <h3>Upcoming Deliveries</h3>
          {deliveries.filter((d) => d.status !== 'completed').length === 0 ? (
            <p className="empty-state">No upcoming deliveries</p>
          ) : (
            <div className="delivery-list">
              {deliveries
                .filter((d) => d.status !== 'completed')
                .slice(0, 5)
                .map((delivery) => (
                  <div key={delivery.id} className="delivery-item">
                    <div
                      style={{
                        display: 'flex',
                        justifyContent: 'space-between',
                        alignItems: 'start',
                        marginBottom: '10px',
                      }}
                    >
                      <h4>{delivery.customer_name}</h4>
                      <span
                        style={{
                          padding: '4px 8px',
                          borderRadius: '4px',
                          fontSize: '0.7rem',
                          color: 'white',
                          backgroundColor: getStatusColor(delivery.status),
                        }}
                      >
                        {delivery.status?.replace('_', ' ')}
                      </span>
                    </div>
                    <p style={{ marginBottom: '5px' }}>
                      <strong>Address:</strong> {delivery.address}
                    </p>
                    <p style={{ marginBottom: '5px' }}>
                      <strong>Date:</strong>{' '}
                      {delivery.scheduled_date
                        ? new Date(delivery.scheduled_date).toLocaleDateString()
                        : 'Not scheduled'}
                    </p>
                    <p>
                      <strong>Items:</strong> {delivery.items?.length || 0}
                    </p>
                  </div>
                ))}
            </div>
          )}
        </div>
      </div>

      <div className="card" style={{ marginTop: '20px' }}>
        <h3>All Deliveries</h3>
        {deliveries.length === 0 ? (
          <p className="empty-state">No deliveries found</p>
        ) : (
          <table>
            <thead>
              <tr>
                <th>ID</th>
                <th>Customer</th>
                <th>Address</th>
                <th>Scheduled Date</th>
                <th>Status</th>
              </tr>
            </thead>
            <tbody>
              {deliveries.map((delivery) => (
                <tr key={delivery.id}>
                  <td>#{delivery.id}</td>
                  <td>{delivery.customer_name}</td>
                  <td>{delivery.address}</td>
                  <td>
                    {delivery.scheduled_date
                      ? new Date(delivery.scheduled_date).toLocaleDateString()
                      : 'Not scheduled'}
                  </td>
                  <td>
                    <span
                      style={{
                        padding: '4px 8px',
                        borderRadius: '4px',
                        color: 'white',
                        backgroundColor: getStatusColor(delivery.status),
                      }}
                    >
                      {delivery.status?.replace('_', ' ')}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>

      {showModal && selectedDate && (
        <div className="modal">
          <div className="modal-content">
            <div className="modal-header">
              <h3>Deliveries for {formatDate(selectedDate)}</h3>
              <button className="modal-close" onClick={() => setShowModal(false)}>
                &times;
              </button>
            </div>
            {selectedDateDeliveries.length === 0 ? (
              <p className="empty-state">No deliveries scheduled for this date</p>
            ) : (
              <div className="delivery-list">
                {selectedDateDeliveries.map((delivery) => (
                  <div key={delivery.id} className="delivery-item">
                    <h4>{delivery.customer_name}</h4>
                    <p>Address: {delivery.address}</p>
                    <p>Status: {delivery.status?.replace('_', ' ')}</p>
                  </div>
                ))}
              </div>
            )}
            <div className="modal-footer">
              <button className="btn btn-primary" onClick={() => setShowModal(false)}>
                Close
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default DeliveryCalendar;
